function makeQRCode(target, url){ const img=document.createElement('img'); img.alt='QR'; img.src='https://chart.googleapis.com/chart?cht=qr&chs=300x300&chl='+encodeURIComponent(url); target.appendChild(img);} window.QRCode={toCanvas:function(canvas,url){ return new Promise(function(resolve){ const parent=canvas.parentNode||document.body; makeQRCode(parent,url); resolve(canvas); }); }};
